async def execute(self, inputs):
    src = self.get_parameter('python_code', '')
    # Allow user to control whether to return result via input/widget 'return_result'
    try:
        return_flag = inputs.get('return_result')
        if return_flag is None:
            return_flag = self.get_parameter('return_result', True)
    except Exception:
        return_flag = True

    # Provide inputs and params to the script in its local namespace
    local_ns = {'inputs': inputs, 'params': self.parameters}
    try:
        exec(src, {'__builtins__': __builtins__}, local_ns)
        res = local_ns.get('result', None)
    except Exception as e:
        # Log and continue
        try:
            self.log_info(f'Python script error: {e}')
        except Exception:
            pass
        res = None

    if return_flag:
        await self.set_output('result', res)
    await self.set_output('exec_out', True)
    return {'result': res} if return_flag else {}
